 1	import * as React from 'react';
 2	import { useGetExternalClusterDetails } from '@odf/core/redux/utils';
 3	import { cephClusterResource } from '@odf/core/resources';
 4	import { getResourceInNs as getCephClusterInNs } from '@odf/core/utils';
 5	import { getCephHealthState } from '@odf/ocs/utils';
 6	import { K8sResourceKind, CephClusterKind } from '@odf/shared/types';
 7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 8	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import { HealthItem } from '@openshift-console/dynamic-plugin-sdk-internal';
10	import {
11	  GalleryItem,
12	  Gallery,
13	  Card,
14	  CardHeader,
15	  CardBody,
16	  CardTitle,
17	} from '@patternfly/react-core';
18	import '../../style.scss';
19	
20	export const StatusCard: React.FC = () => {
21	  const { t } = useCustomTranslation();
22	  const [data, loaded, loadError] =
23	    useK8sWatchResource<K8sResourceKind[]>(cephClusterResource);
24	
25	  const { clusterNamespace: clusterNs } = useGetExternalClusterDetails();
26	
27	  const cephHealth = getCephHealthState(
28	    {
29	      ceph: {
30	        data: getCephClusterInNs(data as CephClusterKind[], clusterNs),
31	        loaded,
32	        loadError,
33	      },
34	    },
35	    t
36	  );
37	
38	  return (
39	    <Card className="odf-overview-card--gradient">
40	      <CardHeader>
41	        <CardTitle>{t('Status')}</CardTitle>
42	      </CardHeader>
43	      <CardBody>
44	        <Gallery className="odf-overview-status__health" hasGutter>
45	          <GalleryItem>
46	            <HealthItem
47	              title={t('Storage Cluster')}
48	              state={cephHealth.state}
49	              details={cephHealth.message}
50	            />
51	          </GalleryItem>
52	        </Gallery>
53	      </CardBody>
54	    </Card>
55	  );
56	};
57	
58	export default StatusCard;

